import{_ as t,o,c as i,a as e,b as a}from"./app-365be48d.js";const n={},s=e("h1",{id:"introduction",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#introduction","aria-hidden":"true"},"#"),a(" Introduction")],-1),r=e("p",null,"In the past years bioinformatics has become a crucial part of several medical laboratories, such as Genetics , Pathology and Medical Microbiology. Hence, bioinformaticians need to comply to both the ISO-15189 and the IVDR.",-1),c=e("p",null,'However, the ISO-15189 does not include bioinformatic or software development processes. Fortunately, the IEC-62304 exists, which is a harmonized standard about "Medical device software – Software life cycle processes". The use of this standard remains voluntary, however, it gives good guidance to demonstrate compliance with legal requirements.',-1),d=e("p",null,"We took the IEC-62304 as a guidance to create a fieldnorm for bioinformatics, to make sure that the software we create is developed and manufactured in accordance with the state-of-the-art taking into account the principles of development life cycle, risk management, including verification and validation, as required by the IVDR (Annex I, point 16).",-1),l=e("p",null,"The main goal of this document is to give guidance to what should be documented to comply to the ISO-15189 and the IVDR. We tried to make pragmatic solutions, and clarity on what should be documented.",-1),h=e("p",null,"While writing this fieldnorm, it became clear that the size of bioinformatics teams differs. In particular, when there is only a single bioinformatician working for the medical laboratory, some of the items described in this fieldnorm will be rather impossible. For example, reviewing each others code will be difficult. While the fieldnorm does describe the needs to comply to the IVDR and the ISO-15189, it might be impossible to comply to the fieldnorm due to the lack of personnel. Make sure choices about no compliance are reasoned and documented, and revise these choices once the team has expanded.",-1),m=e("p",null,"This fieldnorm does not include Personnel (6.2 in ISO-15189:2022), as this should be covered by QMS of the Medical Laboratory already.",-1),u=[s,r,c,d,l,h,m];function f(p,b){return o(),i("div",null,u)}const g=t(n,[["render",f],["__file","index.html.vue"]]);export{g as default};
